<script setup>
import { computed, defineProps } from 'vue'

const props = defineProps({
	value: String,
})

const pressure = computed(() => {
	const match = props.value.match(/(\d+\.?\d*)/)
	return match ? parseFloat(match[1]) : 0
})

const baroPointerAngle = computed(() => {
	const clamp = (value, min, max) => Math.max(min, Math.min(max, value))
	const p = clamp(pressure.value, 960, 1070)

	const center = { x: 125.3969, y: 125.3969 }

	const angleFor = (x, y) => (Math.atan2(y - center.y, x - center.x) * 180) / Math.PI

	const minMid = { x: 96.33555, y: 174.07825 }
	const maxMid = { x: 156.80435, y: 173.24825 }

	const minAngle = angleFor(minMid.x, minMid.y)
	const maxAngle = angleFor(maxMid.x, maxMid.y)

	const pointerTip = { x: 92.9866, y: 79.4587 }
	const baseAngle = angleFor(pointerTip.x, pointerTip.y)

	const t = (p - 960) / (1070 - 960)
	let sweep = maxAngle - minAngle

	if (Math.abs(sweep) < 180) {
		sweep = sweep - Math.sign(sweep || 1) * 360
	}

	const targetAngle = minAngle + t * sweep

	return targetAngle - baseAngle
})
</script>
